 29→    const {isLoading, data, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 30→        queryKey: ['getOpinions'],
 31→        queryFn:({pageParam = null}) => getOpinions(pageParam, 5),
 32→        getNextPageParam: (lastPage) => {
 33→            if(lastPage.hasMore){
 34→                const lastOpinion = lastPage?.data[lastPage?.data.length - 1];
 35→                return lastOpinion.id;
 36→            } else {
 37→                return undefined;
 38→            }
 39→        },
