 43→
 44→    useEffect(() =>{
 45→        // console.log(data);
 46→    }, [data])
 47→
 48→    const getUserHandle = (opinionUser) => {
 49→        if(!opinionUser?.user_email) return null;
 50→        const handle = opinionUser.user_email.split('@')[0];
 51→        return handle ? `@${handle}` : null;
 52→    }
 53→
 54→    const links = [
