177→                            exit={{ opacity: 0, transition: { duration: 0.2, ease: 'easeIn' } }}
178→                        >
179→                            <div className="opinion-fab-icon-wrapper">
180→                                <svg xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink" width="24px" height="24px" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="0.05">
181→                                    <g id="grid_system"/>
182→                                    <g id="_icons">
183→                                        <path d="M22,13.5c0-2.3-1.8-4.2-4-4.5c-0.2-2.8-2.6-5-5.4-5H7.5C6,4,4.6,4.6,3.6,5.6C2.6,6.6,2,8,2,9.5c0,1.2,0.4,2.3,1,3.2l-1,3   c-0.1,0.4,0,0.8,0.3,1.1C2.5,16.9,2.8,17,3,17c0.2,0,0.3,0,0.4-0.1l4-2c0,0,0,0,0,0h1.8c0.2,0.5,0.4,1,0.7,1.4   c0.9,1.1,2.1,1.7,3.5,1.7h2.3l3.8,1.9C19.7,20,19.8,20,20,20c0.2,0,0.5-0.1,0.7-0.2c0.3-0.3,0.4-0.7,0.3-1.1L20.4,17   c0.1-0.1,0.2-0.2,0.3-0.3C21.5,15.8,22,14.7,22,13.5z M7.3,12.9c-0.2,0-0.4,0-0.6,0.1l-2.1,1l0.4-1.3c0.1-0.3,0-0.7-0.2-1   C4.3,11.1,4,10.3,4,9.5C4,8.5,4.4,7.7,5,7c0.7-0.7,1.5-1,2.4-1h5.1c1.8,0,3.2,1.3,3.4,3h-2.5c-1.2,0-2.3,0.5-3.2,1.3   c-0.7,0.7-1.1,1.5-1.3,2.4c0,0.1,0,0.1,0,0.2H7.5C7.4,12.9,7.4,12.9,7.3,12.9z M19.3,15.3c-0.2,0.2-0.4,0.3-0.6,0.4   c-0.4,0.2-0.6,0.7-0.5,1.2l0.1,0.2l-1.8-0.9C16.3,16,16.2,16,16,16h-2.5c-0.8,0-1.5-0.3-2-1c-0.3-0.4-0.5-0.8-0.5-1.2   c0-0.1,0-0.2,0-0.3c0-0.1,0-0.3,0-0.4c0.1-0.5,0.3-1,0.7-1.3c0.5-0.5,1.1-0.7,1.8-0.7H17h0.5c1.4,0,2.5,1.1,2.5,2.5   C20,14.2,19.7,14.8,19.3,15.3z"/>
184→                                    </g>
185→                                </svg>
186→                            </div>
187→                        </motion.div>
188→                    )}
189→
190→                    <div>
191→                        No opinions availabe
192→                    </div>
193→                </div>
194→            </>
195→            </AnimatePresence>
196→        )
197→    }
198→
199→    return(
200→        <AnimatePresence>
201→        <>
202→        {openOpinionEditor && (
203→            <OpinionEditor onClose={closeOpinionEditor}/>
204→        )}
205→
206→        {showHeaders && (
207→            <motion.div 
208→            className="newsfeed-header"
209→            initial={{opacity: 0}}
210→            animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
211→            exit={{ opacity: 0, y: -20,
212→                    transition: { 
213→                    duration: 0.2,
214→                    ease: "easeOut"
215→                    }
216→                }}
217→            >
218→                {links.map((link, index) =>(
219→                    <div onClick={() => handleClickLinks(link.path)} key={index} className='header-link'>
220→                        {link.label}
221→                        <div className={link.path === location.pathname ? "header-underline" : ''}></div>
222→                    </div>
223→                ))}
224→            </motion.div>
225→        )}
226→
227→        
228→        <div className="opinions-page-parent-container">   
229→
230→            {showWriteContainer && (
231→                <motion.div
232→                    className="write-opinion-fab"
233→                    onClick={(e) => handleClickWriteOpinion(e)}
234→                    initial={{ opacity: 0 }}
235→                    animate={{ opacity: 1, transition: { duration: 0.3, ease: 'easeOut' } }}
236→                    exit={{ opacity: 0, transition: { duration: 0.2, ease: 'easeIn' } }}
237→                >
238→                    <div className="opinion-fab-icon-wrapper">
239→                        <svg xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink" width="24px" height="24px" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="0.05">
240→                            <g id="grid_system"/>
241→                            <g id="_icons">
242→                                <path d="M22,13.5c0-2.3-1.8-4.2-4-4.5c-0.2-2.8-2.6-5-5.4-5H7.5C6,4,4.6,4.6,3.6,5.6C2.6,6.6,2,8,2,9.5c0,1.2,0.4,2.3,1,3.2l-1,3   c-0.1,0.4,0,0.8,0.3,1.1C2.5,16.9,2.8,17,3,17c0.2,0,0.3,0,0.4-0.1l4-2c0,0,0,0,0,0h1.8c0.2,0.5,0.4,1,0.7,1.4   c0.9,1.1,2.1,1.7,3.5,1.7h2.3l3.8,1.9C19.7,20,19.8,20,20,20c0.2,0,0.5-0.1,0.7-0.2c0.3-0.3,0.4-0.7,0.3-1.1L20.4,17   c0.1-0.1,0.2-0.2,0.3-0.3C21.5,15.8,22,14.7,22,13.5z M7.3,12.9c-0.2,0-0.4,0-0.6,0.1l-2.1,1l0.4-1.3c0.1-0.3,0-0.7-0.2-1   C4.3,11.1,4,10.3,4,9.5C4,8.5,4.4,7.7,5,7c0.7-0.7,1.5-1,2.4-1h5.1c1.8,0,3.2,1.3,3.4,3h-2.5c-1.2,0-2.3,0.5-3.2,1.3   c-0.7,0.7-1.1,1.5-1.3,2.4c0,0.1,0,0.1,0,0.2H7.5C7.4,12.9,7.4,12.9,7.3,12.9z M19.3,15.3c-0.2,0.2-0.4,0.3-0.6,0.4   c-0.4,0.2-0.6,0.7-0.5,1.2l0.1,0.2l-1.8-0.9C16.3,16,16.2,16,16,16h-2.5c-0.8,0-1.5-0.3-2-1c-0.3-0.4-0.5-0.8-0.5-1.2   c0-0.1,0-0.2,0-0.3c0-0.1,0-0.3,0-0.4c0.1-0.5,0.3-1,0.7-1.3c0.5-0.5,1.1-0.7,1.8-0.7H17h0.5c1.4,0,2.5,1.1,2.5,2.5   C20,14.2,19.7,14.8,19.3,15.3z"/>
243→                            </g>
