260→                                        </div>
261→                                        <div className="so-name-block">
262→                                            <div className="so-name-line">
263→                                                <span onClick={(e) => handleClickOpinionProfile(e, user?.userData[0].id, opinion.user_id)} className="so-username">{opinion.users.name}</span>
