265→                                            </div>
266→                                            {handle && (
267→                                                <span className="so-handle">{handle}</span>
268→                                            )}
269→                                        </div>
270→                                    </div>
271→                                    <div className="so-date-row">
272→                                        <span className="ov-dot">·</span>
273→                                        <span className="ov-date">{formatPostDate(opinion.created_at)}</span>
274→                                    </div>
275→                                </div>
276→                                <div className="so-body" onClick={(e) => handleClickContent(e, opinion.id, opinion.user_id)}>
277→                                    <MentionText text={opinion.opinion} />
278→                                </div>
279→                                <div className="so-meta-bar">
280→                                    <span className="so-reply-pill" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}>
281→                                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
