283→                                        </svg>
284→                                        Reply
285→                                    </span>
286→                                </div>
287→                            </div>
288→                        </div>
289→                    </div>
290→                )
291→            })}
292→            <div className="opinions-in-view" ref={ref}>
293→            </div>
294→        </div>
295→
296→            
297→        </>
298→        </AnimatePresence>
