  1→import { useQuery, useQueryClient } from "@tanstack/react-query";
  2→import { useLocation } from "react-router-dom";
  3→import { addReplyOpinion, getViewOpinion } from "../../../API/Api";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { useState, useRef } from "react";
  6→import { motion, AnimatePresence } from "framer-motion";
  7→import formatPostDate from "../../../helpers/formatDateString";
  8→import OpinionsReplyCard from "./OpinionsCardRepy";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import MentionText from "../mentions/MentionText";
 11→import useTextareaMention from "../mentions/useTextareaMention";
 12→import MentionDropdown from "../mentions/MentionDropdown";
 13→
 14→const OpinionViewer = () => {
 15→    const queryClient = useQueryClient();
 16→    const location = useLocation();
 17→    const { opinionId, userId } = location.state;
 18→    const { user, session } = useAuth();
 19→    const textAreaRef = useRef(null);
 20→
 21→    const [replyOpinion, setReplyOpinion] = useState('');
 22→    const [isTyping, setIsTyping] = useState(false);
 23→
 24→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(replyOpinion, setReplyOpinion, textAreaRef, 280, user?.userData?.[0]?.id);
 25→
 26→    const { data, isLoading } = useQuery({
 27→        queryKey: ['getViewOpinion', opinionId, userId],
 28→        queryFn: ({ queryKey }) => getViewOpinion(queryKey[1], queryKey[2]),
 29→        staleTime: 1000 * 60 * 60,
 30→        gcTime: 1000 * 60 * 60,
 31→        enabled: !!opinionId && !!userId,
 32→        refetchOnWindowFocus: false
 33→    });
 34→
 35→    const cancelTyping = () => {
 36→        setIsTyping(false);
 37→        setReplyOpinion('');
 38→        if (textAreaRef.current) {
 39→            textAreaRef.current.blur();
 40→        }
 41→    };
 42→
 43→    const submitReply = async (receiverId, senderId, parentId) => {
 44→        const formData = new FormData();
 45→        formData.append('opinion', replyOpinion);
 46→
 47→        try {
 48→            await addReplyOpinion(formData, receiverId, senderId, parentId, session?.access_token);
 49→            setReplyOpinion('');
 50→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion', opinionId, userId] });
 51→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 52→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 53→        } catch (error) {
 54→            console.error(error);
 55→            setReplyOpinion('');
 56→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion', opinionId, userId] });
 57→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 58→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 59→        }
 60→    };
 61→
 62→    const opinionData = data?.data;
 63→
 64→    // console.log(opinionData)
 65→
 66→    return (
 67→        <>
 68→            {opinionData?.map((opinion) => (
 69→                <motion.div
 70→                    className="so-card-wrapper"
 71→                    key={opinion.id}
 72→                    initial={{ opacity: 0, y: 12 }}
 73→                    animate={{ opacity: 1, y: 0 }}
 74→                    transition={{ duration: 0.3, ease: "easeOut" }}
 75→                >
 76→                    <div className="so-card so-card--flat">
 77→                        <div className="so-card-content">
 78→                            <div className="so-user-row">
 79→                                <div className="so-user-meta">
 80→                                    <div className={`so-avatar-outer ${opinion.users.badge === 'legend' ? 'avatar-ring-legend' : opinion.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 81→                                        <img
 82→                                            className="so-avatar"
 83→                                            src={opinion.users.image_url || '../assets/profile.jpg'}
 84→                                            alt={`${opinion?.users?.name || "User"} profile picture`}
 85→                                        />
 86→                                    </div>
 87→                                    <div className="so-name-block">
 88→                                        <div className="so-name-line">
 89→                                            <span className="so-username">{opinion.users.name}</span>
 90→                                            <VerifiedBadge badge={opinion.users.badge} size={14}/>
 91→                                        </div>
 92→                                        <span className="so-handle">{formatPostDate(opinion.created_at)}</span>
 93→                                    </div>
 94→                                </div>
 95→                            </div>
 96→
 97→                            <div className="so-body">
 98→                                <MentionText text={opinion.opinion} />
 99→                            </div>
100→
101→                            <div className="so-meta-bar">
102→                                <span className="so-reply-pill">
103→                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
104→                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
105→                                    </svg>
106→                                    {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
107→                                </span>
108→                                <span className="ov-full-date">
109→                                    {new Date(opinion.created_at).toLocaleDateString('en-US', {
110→                                        month: 'long',
111→                                        day: '2-digit',
112→                                        year: 'numeric',
113→                                    })}
114→                                </span>
115→                            </div>
116→
117→                            <div className="ov-reply-row">
118→                                <img
119→                                    className="ov-reply-avatar"
120→                                    src={user?.userData[0].image_url || '../assets/profile.jpg'}
121→                                    alt={`${user?.userData?.[0]?.name || "User"} profile picture`}
122→                                />
123→                                <textarea
124→                                    ref={textAreaRef}
125→                                    maxLength={280}
126→                                    value={replyOpinion}
127→                                    onChange={(e) => { setReplyOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
128→                                    onKeyDown={mentionTextareaProps.onKeyDown}
129→                                    onKeyUp={mentionTextareaProps.onKeyUp}
130→                                    onFocus={() => setIsTyping(true)}
131→                                    className="ov-reply-input"
132→                                    placeholder={`Add a reply to '${opinion.users.name}'`}
133→                                    rows={2}
134→                                />
135→                                <MentionDropdown {...mentionDropdownProps} />
136→                            </div>
137→
138→                            <AnimatePresence>
139→                                {isTyping && (
140→                                    <motion.div
141→                                        className="ov-btn-row"
142→                                        initial={{ height: 0, opacity: 0 }}
143→                                        animate={{ height: "auto", opacity: 1 }}
144→                                        exit={{ height: 0, opacity: 0 }}
145→                                        transition={{ duration: 0.2 }}
146→                                    >
147→                                        <button
148→                                            onClick={cancelTyping}
149→                                            className="ov-btn-cancel"
150→                                        >
151→                                            Cancel
152→                                        </button>
153→                                        <button
154→                                            disabled={replyOpinion.trim().length === 0}
155→                                            onClick={() => submitReply(userId, user?.userData[0].id, opinion.id)}
156→                                            className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
157→                                        >
158→                                            Submit
159→                                        </button>
160→                                    </motion.div>
161→                                )}
162→                            </AnimatePresence>
163→
164→                            <OpinionsReplyCard opinionId={opinion.id} depth={0} />
165→                        </div>
166→                    </div>
167→                </motion.div>
168→            ))}
169→        </>
170→    );
171→};
